ALGORITHM System_Call_Invocation
INPUT: system_call_number, parameters[]
OUTPUT: result or error_code

BEGIN
 // Step 1: User program prepares parameters
 SET syscall_num TO system_call_number
 SET params TO parameters

 // Step 2: Place system call number in designated register
 REGISTER[EAX] = syscall_num

 // Step 3: Place parameters in appropriate registers/blocks
 // (Using register method for demonstration)
 REGISTER[EBX] = params[0] // First parameter (e.g., file descriptor)
 REGISTER[ECX] = params[1] // Second parameter (e.g., buffer address)
 REGISTER[EDX] = params[2] // Third parameter (e.g., byte count)

 // Step 4: Execute TRAP instruction (software interrupt)
 // This switches CPU from user mode to kernel mode
 EXECUTE TRAP instruction

 // --- CPU is now in KERNEL MODE ---

 // Step 5: Kernel saves current process state
 SAVE_PROCESS_STATE()

 // Step 6: Kernel validates system call number
 IF syscall_num >= MAX_SYSTEM_CALLS THEN
 RETURN ERROR_INVALID_SYSCALL
 END IF

 // Step 7: Kernel looks up handler in system call table
 SET handler TO SYSTEM_CALL_TABLE[syscall_num]

 // Step 8: Kernel dispatches to appropriate handler
 SET result TO CALL_FUNCTION(handler, params)

 // Step 9: Place result in return register
 REGISTER[EAX] = result

 // Step 10: Restore process state and return to user mode
 RESTORE_PROCESS_STATE()
 EXECUTE RETURN_FROM_TRAP

 // --- CPU is now back in USER MODE ---

 // Step 11: Return result to caller
 RETURN REGISTER[EAX]
END

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <string.h>

/*
 * C Program demonstrating direct system calls in UNIX/Linux
 * These functions directly invoke the corresponding kernel system calls:
 * - open, read, write, close -> sys_open, sys_read, sys_write, sys_close
 * - fork, getpid, getuid -> sys_fork, sys_getpid, sys_getuid
 * - unlink, mkdir, rmdir -> sys_unlink, sys_mkdir, sys_rmdir
 */

#define BUFFER_SIZE 256

void demonstrate_file_system_calls(const char *filename) {
 printf("=== File System System Calls Demo ===\n\n");

 /* System Call: open() 
 * In kernel: Maps to sys_open()
 * Parameters: filename, flags, mode
 * Returns: file descriptor (non-negative) or -1 on error
 */
 int fd = open(filename, O_CREAT | O_WRONLY | O_TRUNC, 0644);
 if (fd < 0) {
 perror("open system call failed");
 return;
 }
 printf("[System Call] open(\"%s\") returned fd: %d\n", filename, fd);

 /* System Call: write()
 * In kernel: Maps to sys_write()
 * Parameters: fd, buffer, count
 * Returns: number of bytes written or -1 on error
 */
 const char *message = "Hello from C using direct system calls!\n";
 ssize_t bytes_written = write(fd, message, strlen(message));
 printf("[System Call] write() wrote %zd bytes\n", bytes_written);

 /* System Call: close()
 * In kernel: Maps to sys_close()
 * Parameter: file descriptor
 * Returns: 0 on success, -1 on error
 */
 close(fd);
 printf("[System Call] close(%d) succeeded\n", fd);

 /* Reopen for reading */
 int fd_read = open(filename, O_RDONLY);
 printf("[System Call] open(\"%s\", O_RDONLY) returned fd: %d\n", 
 filename, fd_read);

 /* System Call: read()
 * In kernel: Maps to sys_read()
 * Parameters: fd, buffer, count
 * Returns: number of bytes read or -1 on error
 */
 char buffer[BUFFER_SIZE];
 ssize_t bytes_read = read(fd_read, buffer, BUFFER_SIZE - 1);
 if (bytes_read > 0) {
 buffer[bytes_read] = '\0';
 printf("[System Call] read() read: %s", buffer);
 }

 close(fd_read);

 /* System Call: unlink()
 * In kernel: Maps to sys_unlink()
 * Parameter: filename
 * Returns: 0 on success, -1 on error
 */
 unlink(filename);
 printf("[System Call] unlink(\"%s\") deleted the file\n", filename);
}

void demonstrate_process_system_calls(void) {
 printf("\n=== Process Management System Calls Demo ===\n\n");

 /* System Call: getpid()
 * In kernel: Maps to sys_getpid()
 * Returns: process ID of calling process
 */
 pid_t my_pid = getpid();
 printf("[System Call] getpid() returned: %d\n", my_pid);

 /* System Call: getuid()
 * In kernel: Maps to sys_getuid()
 * Returns: real user ID of calling process
 */
 uid_t my_uid = getuid();
 printf("[System Call] getuid() returned: %d\n", my_uid);

 /* System Call: fork()
 * In kernel: Maps to sys_fork()
 * Returns: 0 in child, child's PID in parent, -1 on error
 */
 pid_t child_pid = fork();

 if (child_pid < 0) {
 perror("fork system call failed");
 return;
 }

 if (child_pid == 0) {
 /* Child process */
 printf("[Child] fork() returned 0\n");
 printf("[Child] My PID: %d, Parent PID: %d\n", getpid(), getppid());

 /* System Call: _exit()
 * In kernel: Maps to sys_exit()
 * Parameter: exit status
 */
 _exit(0);
 } else {
 /* Parent process */
 printf("[Parent] fork() returned child PID: %d\n", child_pid);

 /* System Call: waitpid()
 * In kernel: Maps to sys_wait4()
 * Parameters: pid, status, options
 * Returns: PID of terminated child or -1 on error
 */
 int status;
 waitpid(child_pid, &status, 0);
 printf("[Parent] Child process terminated with status: %d\n", WEXITSTATUS(status));
 }
}

void demonstrate_directory_system_calls(const char *test_dir) {
 printf("\n=== Directory System Calls Demo ===\n\n");

 /* System Call: getcwd()
 * In kernel: Maps to sys_getcwd()
 * Parameters: buffer, size
 * Returns: pointer to buffer on success, NULL on error
 */
 char cwd[BUFFER_SIZE];
 if (getcwd(cwd, BUFFER_SIZE) != NULL) {
 printf("[System Call] getcwd() returned: %s\n", cwd);
 }

 /* System Call: mkdir()
 * In kernel: Maps to sys_mkdir()
 * Parameters: pathname, mode
 * Returns: 0 on success, -1 on error
 */
 if (mkdir(test_dir, 0755) == 0) {
 printf("[System Call] mkdir(\"%s\") created directory\n", test_dir);
 }

 /* System Call: rmdir()
 * In kernel: Maps to sys_rmdir()
 * Parameter: pathname
 * Returns: 0 on success, -1 on error
 */
 if (rmdir(test_dir) == 0) {
 printf("[System Call] rmdir(\"%s\") removed directory\n", test_dir);
 }
}

int main(void) {
 const char *filename = "demo_c_syscalls.txt";
 const char *test_dir = "test_syscall_dir_c";

 printf("C Direct System Calls Demonstration\n");
 printf("====================================\n\n");

 demonstrate_file_system_calls(filename);
 demonstrate_process_system_calls();
 demonstrate_directory_system_calls(test_dir);

 printf("\n====================================\n");
 printf("All system calls executed successfully!\n");

 return 0;
}
